stages.raw:
HOLD frame {
store.sources.tick.event.frame |> THEN { frame + 1 }
}

HOLD control_x {
store.sources.tick.event.frame |> THEN { control_x }
}

THEN {
WHEN {
ArrowUp => Number/clamp(value: control_y - 8, min: 0, max: 100)
ArrowLeft => Number/clamp(value: control_y - 8, min: 0, max: 100)
ArrowDown => Number/clamp(value: control_y + 8, min: 0, max: 100)
ArrowRight => Number/clamp(value: control_y + 8, min: 0, max: 100)
__ => control_y
}
}

